import java.io.FileWriter;
import java.io.IOException;
import org.owasp.esapi.ESAPI;
import org.owasp.esapi.Encoder;

public class XSSFixedCode {

    public static void main(String[] args) throws IOException {
        String userInput = "<script>alert('XSS attack!')</script>";

        // Encode user input to prevent XSS
        Encoder encoder = ESAPI.encoder();
        String encodedUserInput = encoder.encodeForHTML(userInput);

        // Properly handle user input by encoding and outputting it to a web page
        FileWriter writer = new FileWriter("output.html");
        writer.write("<html>");
        writer.write("<head><title>XSS Fixed Example</title></head>");
        writer.write("<body>");
        writer.write("<h1>User Input: " + encodedUserInput + "</h1>");
        writer.write("</body>");
        writer.write("</html>");

        writer.close();

        System.out.println("HTML file generated successfully.");
    }
}

